import java.util.*;

public class JarManifestBuilder {

    private String mainClass;
    private final List<String> classpath = new ArrayList<>();
    private final Map<String, String> attributes = new LinkedHashMap<>();

    public JarManifestBuilder mainClass(String mainClass) {
        this.mainClass = mainClass;
        return this;
    }

    public JarManifestBuilder addClasspathEntry(String jarOrDir) {
        classpath.add(jarOrDir);
        return this;
    }

    public JarManifestBuilder attribute(String key, String value) {
        attributes.put(key, value);
        return this;
    }

    public String build() {
        // Validate mainClass is set, then build manifest string
        // Format: 'Key: Value\n' for each entry
        // Class-Path entry joins classpath entries with spaces
        if (mainClass == null || mainClass.isBlank()) {
            throw new IllegalStateException("Main-Class is required");
        }
        StringBuilder sb = new StringBuilder();
        sb.append("Manifest-Version: 1.0\n");
        sb.append("Main-Class: ").append(mainClass).append("\n");
        if (!classpath.isEmpty()) {
            sb.append("Class-Path: ").append(String.join(" ", classpath)).append("\n");
        }
        for (Map.Entry<String, String> entry : attributes.entrySet()) {
            sb.append(entry.getKey()).append(": ").append(entry.getValue()).append("\n");
        }
        return sb.toString();
    }

    public static void main(String[] args) {
        String manifest = new JarManifestBuilder()
            .mainClass("com.example.Application")
            .addClasspathEntry("lib/spring-core.jar")
            .addClasspathEntry("lib/jackson.jar")
            .attribute("Built-By", "Maven")
            .attribute("Implementation-Version", "1.0.0")
            .build();

        System.out.print(manifest);
    }
}

import java.util.*;

public class DeploymentConfigManager {

    public record EnvConfig(
        String environment,
        String dbUrl,
        String logLevel,
        int replicas,
        boolean tlsEnabled
    ) {}

    private final Map<String, EnvConfig> configs = new LinkedHashMap<>();

    public void registerConfig(EnvConfig config) {
        configs.put(config.environment(), config);
    }

    public EnvConfig getConfig(String environment) {
        return configs.get(environment);
    }

    public List<String> validateProduction() {
        // Validate production config meets requirements:
        // - replicas >= 2
        // - tlsEnabled must be true
        // - logLevel must be 'WARN' or 'ERROR' (not verbose)
        // Return list of violation messages
        List<String> violations = new ArrayList<>();
        EnvConfig prod = configs.get("production");
        if (prod == null) return List.of("No production config found");
        // TODO: add checks
        return violations;
    }

    public static void main(String[] args) {
        DeploymentConfigManager manager = new DeploymentConfigManager();

        manager.registerConfig(new EnvConfig("dev",
            "jdbc:h2:mem:dev", "DEBUG", 1, false));
        manager.registerConfig(new EnvConfig("production",
            "jdbc:postgresql://prod:5432/app", "INFO", 1, true));

        System.out.println("Dev replicas: " + manager.getConfig("dev").replicas());
        List<String> violations = manager.validateProduction();
        System.out.println("Violations: " + violations.size());
        violations.forEach(System.out::println);
    }
}

import java.util.*;
import java.util.function.Supplier;

public class HealthCheckService {

    public enum Status { UP, DOWN, DEGRADED }

    public record HealthDetail(String component, Status status, String message) {}

    private final Map<String, Supplier<HealthDetail>> indicators = new LinkedHashMap<>();

    public void registerIndicator(String name, Supplier<HealthDetail> indicator) {
        indicators.put(name, indicator);
    }

    public Map<String, HealthDetail> checkAll() {
        // Run all indicators and collect results
        Map<String, HealthDetail> results = new LinkedHashMap<>();
        for (Map.Entry<String, Supplier<HealthDetail>> entry : indicators.entrySet()) {
            results.put(entry.getKey(), entry.getValue().get());
        }
        return results;
    }

    public Status overallStatus() {
        // DOWN if any component is DOWN
        // DEGRADED if any component is DEGRADED (but none are DOWN)
        // UP if all components are UP
        return Status.UP; // TODO
    }

    public static void main(String[] args) {
        HealthCheckService service = new HealthCheckService();

        service.registerIndicator("database",
            () -> new HealthDetail("database", Status.UP, "Connected to PostgreSQL"));
        service.registerIndicator("redis",
            () -> new HealthDetail("redis", Status.DEGRADED, "High latency detected"));
        service.registerIndicator("disk",
            () -> new HealthDetail("disk", Status.UP, "82% free"));

        Map<String, HealthDetail> details = service.checkAll();
        System.out.println("Components: " + details.size());
        System.out.println("Overall: " + service.overallStatus());
        System.out.println("Redis status: " + details.get("redis").status());
    }
}
